perform:
if (object.location === player.id) {
  return lib.result("You are already wearing the " + lib.ref(object) + ". It feels light and cool against your skin.");
}

var moveEvent = lib.moveEvent(object.id, { to: player.id, from: object.location, description: "Player put on the suit" });
return {
  output: "You slide into the " + lib.ref(object) + ". The fabric is impossibly thin but provides a comforting layer of insulation against the chilled air of the bay. The AARU patch sits clean on your shoulder.",
  events: [moveEvent]
};

if (object.properties.systemStatus === 'operational') {
  return lib.result("The terminal pulses with a soft blue light as you touch the screen. The text 'COGNITIVE ASSESSMENT AVAILABLE' blinks expectantly. It seems to be waiting for you to 'BEGIN'.");
} else {
  return lib.result("The screen is dark and unresponsive to your touch.");
}

if (object.properties.systemStatus !== 'operational') {
  return lib.result("The terminal is dark and silent, its circuits dead to your voice.");
}
return lib.result("The terminal emits a soft chime. A cursor blinks on the screen, and the text COGNITIVE ASSESSMENT AVAILABLE pulses gently, as if waiting for you to type 'BEGIN'.");

if (object.properties.systemStatus === 'operational') {
  return lib.result('The sweeper bot is already humming along, bumping gently into the walls.');
}

return {
  output: 'You find a recessed toggle beneath the bot\'s sensor dome and flip it. The machine chirps a melodic, centuries-old startup chime. Its brushes begin to whir, sending a small cloud of dust into the air, and it begins to rotate slowly, its knitted hat wobbling but staying firmly in place.',
  events: [
    lib.setEvent(object.id, { property: 'systemStatus', value: 'operational', description: 'Robot activated' }),
    lib.setEvent(object.id, { property: 'name', value: 'Active Sweeper Bot', description: 'Updated name' }),
    lib.setEvent(object.id, { property: 'description', value: 'A low, disc-shaped machine wearing a small knitted hat. It hums with ancient purpose, its brushes spinning as it performs a methodical, if somewhat erratic, cleaning pattern across the floor.', description: 'Updated description' })
  ]
};

if (object.properties.description.includes('frost')) {
  return lib.result("The frost on the sealed pods is searingly cold, leaving a bitter, metallic tang on your tongue that makes your teeth ache.");
}
return lib.result("You gingerly lick the edge of your vacated pod. It tastes of sterile polymers and a faint, cloying sweetness from the preservation fluids.");

if (object.properties.automated || object.properties.switchedOn) {
  return lib.result("The Sweeper Unit is already humming softly, its blue sensor pulsing as it tracks a stray particle across the deck.");
} else {
  return {
    output: "You find a small, recessed toggle beneath the ribbon on its antenna. With a soft chime, the unit's sensor glows blue and its brushes begin to whirl.",
    events: [lib.setEvent(object.id, { property: "switchedOn", value: true, description: "Unit activated" })]
  };
}

return {
  output: "You bite into the pulsing pith-fruit. The skin resists for a second before yielding with a soft, bioluminescent pop. The flesh is cool, fiberless, and tastes like rain on warm metal with a lingering hint of ozone. For a few moments after you swallow, your own fingertips seem to pulse with a faint, rhythmic glow before fading back to normal.",
  events: [lib.moveEvent(object.id, { to: "void", from: player.id, description: "The pulsing pith-fruit was eaten by the player." })]
};

if (!object.properties.locked) {
  return lib.result("The " + lib.ref(object) + " is already unlocked.");
}

var key = lib.findKey(object);
if (key) {
  var res = lib.unlock(object);
  res.output = "You input the authorization sequence from the " + lib.ref(key) + ". With a heavy hydraulic hiss, the massive circular door rotates and slides into the wall.";
  return res;
} else {
  return lib.result("The " + lib.ref(object) + " requires a specific authorization code or physical keycard to cycle. The terminal next to it pulses a steady, expectant amber.");
}

if (!indirect || indirect.id !== 'device:tuning-slide-console') {
  return lib.result('You blow a clear, resonant note on the bone pipe, but without the console to amplify the harmonics, the sound simply fades into the mist.');
}

var output = 'You hold the translucent bone pipe against the vibrating wires of the console and blow a steady, low note. The pitch pipe glows with a soft, bioluminescent inner light as it syncs with the console\'s frequency. Below you, in the misty depths of the cistern, you hear the heavy, rhythmic grinding of stone on stone. The massive water basins are shifting, rotating with a groaning weight until they lock into a new configuration, forming a series of damp, stepped platforms leading further down.';

var event = lib.createEvent('item:basin-steps', {
  tags: ['scenery'],
  properties: {
    name: 'Basin Steps',
    description: 'The massive stone basins have realigned themselves into a steep, spiral staircase descending into the lower levels.',
    location: room.id
  },
  description: 'The water basins shifted to form steps.'
});

return {
  output: output,
  events: [event]
};
